(function(){const logoSource='https://drive.google.com/uc?id=1dfSKTkPgHFAvW8RiIFludY6hstSshDHH';const failedMessage='Failed to connect to Google Drive. The network you are on may be blocking it. Some files/images may not be shown.';const init=()=>{if($docsify.driveAccessible===undefined){let image=new Image();image.onerror=()=>{console.error(failedMessage);$docsify.driveAccessible=!1};image.onload=()=>{$docsify.driveAccessible=!0};image.src=logoSource}};const before=content=>{init();return!$docsify.driveAccessible?'!> '+failedMessage+'\n\n'+content:content};const driveCheck=hook=>{hook.beforeEach(content=>{return before(content)})};$docsify.plugins=[].concat(driveCheck,$docsify.plugins)}())